#include "interface.h"

#include <algorithm>
#include <utility>
#include <vector>

namespace {

bool better(const std::pair<int32_t, int>& a, const std::pair<int32_t, int>& b) {
  return a.first > b.first || (a.first == b.first && a.second < b.second);
}

uint64_t mix(uint64_t hash, uint64_t value) {
  hash ^= value;
  hash *= 1099511628211ULL;
  return hash;
}

}  // namespace

uint64_t moe_router_checksum(const std::vector<int32_t>& logits, int tokens, int experts, int iters) {
  uint64_t hash = 0;
  for (int iter = 0; iter < iters; ++iter) {
    hash = 1469598103934665603ULL;
    for (int t = 0; t < tokens; ++t) {
      int32_t best1_logit = logits[static_cast<std::size_t>(t) * static_cast<std::size_t>(experts) + 0];
      int best1_idx = 0;
      int32_t best2_logit = logits[static_cast<std::size_t>(t) * static_cast<std::size_t>(experts) + 1];
      int best2_idx = 1;

      if (better({best2_logit, best2_idx}, {best1_logit, best1_idx})) {
        std::swap(best1_logit, best2_logit);
        std::swap(best1_idx, best2_idx);
      }

      for (int e = 2; e < experts; ++e) {
        int32_t current_logit = logits[static_cast<std::size_t>(t) * static_cast<std::size_t>(experts) + e];
        int current_idx = e;
        if (better({current_logit, current_idx}, {best1_logit, best1_idx})) {
          best2_logit = best1_logit;
          best2_idx = best1_idx;
          best1_logit = current_logit;
          best1_idx = current_idx;
        } else if (better({current_logit, current_idx}, {best2_logit, best2_idx})) {
          best2_logit = current_logit;
          best2_idx = current_idx;
        }
      }

      hash = mix(hash, static_cast<uint64_t>(static_cast<uint32_t>(best1_logit)));
      hash = mix(hash, static_cast<uint64_t>(best1_idx));
      hash = mix(hash, static_cast<uint64_t>(static_cast<uint32_t>(best2_logit)));
      hash = mix(hash, static_cast<uint64_t>(best2_idx));
    }
  }
  return hash;
}
